 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	import classNames from 'classnames';
 3	
 4	import { useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 5	import { Menu, MenuContent, MenuItem, MenuList, TooltipPosition } from '@patternfly/react-core';
 6	
 7	import { ActionDropdownItemType } from '../ActionsDropdown/constants';
 8	
 9	import './action-dropdown-item.scss';
10	
11	type ActionDropdownItemProps = {
12	  action: ActionDropdownItemType;
13	  setIsOpen: Dispatch<SetStateAction<boolean>>;
14	};
15	
16	const ActionDropdownItem: FC<ActionDropdownItemProps> = ({ action, setIsOpen }) => {
17	  const [accessReview] = useAccessReview(action?.accessReview || {});
18	
19	  const actionAllowed = accessReview || action?.accessReview === undefined;
20	  const isDisabled = !actionAllowed || action?.disabled;
21	  const displayDisabledTooltip = isDisabled && action?.disabledTooltip;
22	
23	  const handleClick = () => {
24	    if (typeof action?.cta === 'function') {
25	      action?.cta();
26	      setIsOpen(false);
27	    }
28	  };
29	
30	  const tooltipProps = displayDisabledTooltip
31	    ? {
32	        content: action?.disabledTooltip,
33	        position: TooltipPosition.left,
34	      }
35	    : null;
36	
37	  return (
38	    <MenuItem
39	      className={classNames('ActionDropdownItem', {
40	        ActionDropdownItem__disabled: isDisabled,
41	      })}
42	      flyoutMenu={
43	        action?.options && (
44	          <Menu containsFlyout id={`menu-${action.id}`}>
45	            <MenuContent>
46	              <MenuList>
47	                {action?.options?.map((option) => (
48	                  <ActionDropdownItem action={option} key={option.id} setIsOpen={setIsOpen} />
49	                ))}
50	              </MenuList>
51	            </MenuContent>
52	          </Menu>
53	        )
54	      }
55	      data-test-id={`${action?.id}`}
56	      description={action?.description}
57	      isDisabled={isDisabled}
58	      key={action?.id}
59	      onClick={handleClick}
60	      tooltipProps={tooltipProps}
61	    >
62	      {action?.label}
63	      {action?.icon && (
64	        <>
65	          {' '}
66	          <span className="text-muted">{action.icon}</span>
67	        </>
68	      )}
69	    </MenuItem>
70	  );
71	};
72	
73	export default ActionDropdownItem;

